import React from 'react';
import Header from './components/Header';
import HeroBanner from './components/HeroBanner';
import TheEditSection from './components/TheEditSection';
import MensBanner from './components/MensBanner';
import MensEditSection from './components/MensEditSection';
import CollabBanner from './components/CollabBanner';
import EyewearEditSection from './components/EyewearEditSection';

const womenProducts = [
  {
    id: 1,
    name: 'SINGULAR TOTE PIN (BLACK)',
    price: '325,000 KRW',
    bg: '#d0cec8',
    imgBg: '#b8b5ae',
    showHover: false,
  },
  {
    id: 2,
    name: 'DRAPE DETAIL SUIT JACKET (IVORY)',
    price: '321,000 KRW',
    bg: '#e8e5de',
    imgBg: '#f0ede6',
    showHover: false,
  },
  {
    id: 3,
    name: 'OPEN BACK HIGH NECK DRESS (BLACK)',
    price: '295,000 KRW',
    bg: '#d8d5ce',
    imgBg: '#c8c5be',
    showHover: true,
  },
];

function App() {
  return (
    <div className="app">
      <Header />
      <main>
        <HeroBanner />
        <TheEditSection products={womenProducts} />
        <MensBanner />
        <MensEditSection />
        <CollabBanner />
        <EyewearEditSection />
      </main>
    </div>
  );
}

export default App;
